31:   Request(nsIGlobalObject* aOwner, SafeRefPtr<InternalRequest> aRequest,
32:           AbortSignal* aSignal);
33: 
34:   JSObject* WrapObject(JSContext* aCx,
35:                        JS::Handle<JSObject*> aGivenProto) override {
36:     return Request_Binding::Wrap(aCx, this, aGivenProto);
37:   }
38: 
39:   void GetUrl(nsACString& aUrl) const { mRequest->GetURL(aUrl); }
40:   void GetMethod(nsCString& aMethod) const { aMethod = mRequest->mMethod; }
41: 
42:   RequestMode Mode() const { return mRequest->mMode; }
43: 
44:   RequestCredentials Credentials() const { return mRequest->mCredentialsMode; }
45: 
46:   RequestCache Cache() const { return mRequest->GetCacheMode(); }
47: 
48:   RequestRedirect Redirect() const { return mRequest->GetRedirectMode(); }
49: 
50:   RequestPriority Priority() const { return mRequest->GetPriorityMode(); }
51: 
52:   void GetIntegrity(nsAString& aIntegrity) const {
53:     aIntegrity = mRequest->GetIntegrity();
54:   }
55: 
56:   bool Keepalive() const { return mRequest->GetKeepalive(); }
57: 
58:   bool MozErrors() const { return mRequest->MozErrors(); }
59: 
60:   RequestDestination Destination() const { return mRequest->Destination(); }
61: 
62:   void OverrideContentPolicyType(uint32_t aContentPolicyType) {
63:     mRequest->OverrideContentPolicyType(
64:         static_cast<nsContentPolicyType>(aContentPolicyType));
