66: 
67:   bool IsContentPolicyTypeOverridden() const {
68:     return mRequest->IsContentPolicyTypeOverridden();
69:   }
70: 
71:   void GetReferrer(nsACString& aReferrer) const {
72:     mRequest->GetReferrer(aReferrer);
73:   }
74: 
75:   ReferrerPolicy ReferrerPolicy_() const { return mRequest->ReferrerPolicy_(); }
76: 
77:   InternalHeaders* GetInternalHeaders() const { return mRequest->Headers(); }
78: 
79:   Headers* Headers_();
80: 
81:   using FetchBody::GetBody;
82: 
83:   void GetBody(nsIInputStream** aStream, int64_t* aBodyLength = nullptr) {
84:     mRequest->GetBody(aStream, aBodyLength);
85:   }
86: 
87:   void SetBody(nsIInputStream* aStream, int64_t aBodyLength) {
88:     mRequest->SetBody(aStream, aBodyLength);
89:   }
90: 
91:   using FetchBody::BodyBlobURISpec;
92: 
93:   const nsACString& BodyBlobURISpec() const {
94:     return mRequest->BodyBlobURISpec();
95:   }
96: 
97:   using FetchBody::BodyLocalPath;
98: 
99:   const nsAString& BodyLocalPath() const { return mRequest->BodyLocalPath(); }
100: 
101:   static SafeRefPtr<Request> Constructor(const GlobalObject& aGlobal,
102:                                          const RequestOrUTF8String& aInput,
103:                                          const RequestInit& aInit,
104:                                          ErrorResult& rv);
105: 
106:   static SafeRefPtr<Request> Constructor(nsIGlobalObject* aGlobal,
107:                                          JSContext* aCx,
108:                                          const RequestOrUTF8String& aInput,
109:                                          const RequestInit& aInit,
110:                                          const CallerType aCallerType,
111:                                          ErrorResult& rv);
112: 
113:   nsIGlobalObject* GetParentObject() const { return mOwner; }
114: 
115:   SafeRefPtr<Request> Clone(ErrorResult& aRv);
116: 
117:   SafeRefPtr<InternalRequest> GetInternalRequest();
118: 
119:   const UniquePtr<mozilla::ipc::PrincipalInfo>& GetPrincipalInfo() const {
120:     return mRequest->GetPrincipalInfo();
121:   }
122: 
123:   AbortSignal* GetOrCreateSignal();
124: 
125:   // This can return a null AbortSignalImpl.
126:   AbortSignalImpl* GetSignalImpl() const override;
127:   AbortSignalImpl* GetSignalImplToConsumeBody() const final;
